diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..c99699cdd55c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2229,6 +2229,24 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return BitOp;
     }

+    // Handle variable shift amounts with known in-range values.
+    Value *ShAmt = II->getArgOperand(2);
+    KnownBits ShAmtKnown =
+        llvm::computeKnownBits(ShAmt, DL, 0, &AC, II, &DT);
+    // Also check constant range which can include range attribute information.
+    ConstantRange ShAmtCR =
+        llvm::computeConstantRange(ShAmt, /*ForSigned=*/false, /*UseInstrInfo=*/true,
+                                   &AC, II, &DT);
+    if (ShAmtKnown.getMaxValue().ult(BitWidth) ||
+        ShAmtCR.getUnsignedMax().ult(BitWidth)) {
+      // fshl(X, 0, Y) --> shl X, Y if Y is in [0, BitWidth)
+      if (IID == Intrinsic::fshl && match(Op1, m_ZeroInt()))
+        return BinaryOperator::CreateShl(Op0, ShAmt);
+      // fshr(X, 0, Y) --> lshr X, Y if Y is in [0, BitWidth)
+      if (IID == Intrinsic::fshr && match(Op1, m_ZeroInt()))
+        return BinaryOperator::CreateLShr(Op0, ShAmt);
+    }
+
     // Left or right might be masked.
     if (SimplifyDemandedInstructionBits(*II))
       return &CI;

